35: type Migrator struct {
36: 	DBEngine     *xorm.Engine
37: 	Dialect      Dialect
38: 	migrations   []Migration
39: 	migrationIds map[string]struct{}
40: 	Logger       log.Logger
41: 	Cfg          *setting.Cfg
42: 	isLocked     atomic.Bool
