49: type MigrationLog struct {
50: 	Id          int64
51: 	MigrationID string `xorm:"migration_id"`
52: 	SQL         string `xorm:"sql"`
53: 	Success     bool
54: 	Error       string
55: 	Timestamp   time.Time
56: }
