64: func NewMigrator(engine *xorm.Engine, cfg *setting.Cfg) *Migrator {
65: 	return NewScopedMigrator(engine, cfg, "")
66: }
67: 
68: // NewScopedMigrator should only be used for the transition to a new storage engine
69: func NewScopedMigrator(engine *xorm.Engine, cfg *setting.Cfg, scope string) *Migrator {
70: 	mg := &Migrator{
71: 		Cfg:          cfg,
72: 		DBEngine:     engine,
73: 		migrations:   make([]Migration, 0),
74: 		migrationIds: make(map[string]struct{}),
75: 		Dialect:      NewDialect(engine.DriverName()),
76: 		metrics: migratorMetrics{
77: 			migCount: prometheus.NewCounterVec(prometheus.CounterOpts{
78: 				Namespace: "grafana_database",
79: 				Subsystem: scope,
80: 				Name:      "migrations_total",
81: 				Help:      "Total number of SQL migrations",
82: 			}, []string{"success"}),
83: 			migDuration: metricutil.NewHistogramVec(prometheus.HistogramOpts{
84: 				Namespace: "grafana_database",
85: 				Subsystem: scope,
86: 				Name:      "migration_duration_seconds",
87: 				Help:      "Individual SQL migration duration in seconds",
88: 			}, []string{"success"}),
89: 			totalMigDuration: metricutil.NewHistogramVec(prometheus.HistogramOpts{
90: 				Namespace: "grafana_database",
91: 				Subsystem: scope,
92: 				Name:      "all_migrations_duration_seconds",
93: 				Help:      "Duration of the entire SQL migration process in seconds",
94: 			}, []string{"success"}),
95: 		},
96: 	}
97: 	if scope == "" {
98: 		mg.tableName = "migration_log"
99: 		mg.Logger = log.New("migrator")
100: 	} else {
101: 		mg.tableName = scope + "_migration_log"
102: 		mg.Logger = log.New(scope + "-migrator")
103: 	}
104: 	return mg
105: }
