107: // Collect implements Prometheus.Collector.
108: func (mg *Migrator) Collect(ch chan<- prometheus.Metric) {
109: 	mg.metrics.migCount.Collect(ch)
110: 	mg.metrics.migDuration.Collect(ch)
111: 	mg.metrics.totalMigDuration.Collect(ch)
112: }
113: 
114: // Describe implements Prometheus.Collector.
115: func (mg *Migrator) Describe(ch chan<- *prometheus.Desc) {
116: 	mg.metrics.migCount.Describe(ch)
117: 	mg.metrics.migDuration.Describe(ch)
118: 	mg.metrics.totalMigDuration.Describe(ch)
