121: // AddCreateMigration adds the initial migration log table -- this should likely be
122: // automatic and first, but enough tests exists that do not expect that we can keep it explicit
123: func (mg *Migrator) AddCreateMigration() {
124: 	mg.AddMigration("create "+mg.tableName+" table", NewAddTableMigration(Table{
125: 		Name: mg.tableName,
126: 		Columns: []*Column{
127: 			{Name: "id", Type: DB_BigInt, IsPrimaryKey: true, IsAutoIncrement: true},
128: 			{Name: "migration_id", Type: DB_NVarchar, Length: 255},
129: 			{Name: "sql", Type: DB_Text},
130: 			{Name: "success", Type: DB_Bool},
131: 			{Name: "error", Type: DB_Text},
132: 			{Name: "timestamp", Type: DB_DateTime},
133: 		},
134: 	}))
135: }
