305: func (mg *Migrator) doMigration(ctx context.Context, m Migration) error {
306: 	ctx, span := tracer.Start(ctx, "Migrator.doMigration", trace.WithAttributes(
307: 		attribute.String("migration_id", m.Id()),
308: 	))
309: 	defer span.End()
310: 
311: 	logger := mg.Logger.FromContext(ctx)
312: 
313: 	sql := m.SQL(mg.Dialect)
314: 
315: 	record := MigrationLog{
316: 		MigrationID: m.Id(),
317: 		SQL:         sql,
318: 		Timestamp:   time.Now(),
319: 	}
320: 
321: 	err := mg.InTransaction(func(sess *xorm.Session) error {
322: 		// propagate context
323: 		sess = sess.Context(ctx)
324: 
325: 		err := mg.exec(ctx, m, sess)
326: 		// if we get an sqlite busy/locked error, sleep 100ms and try again
327: 		cnt := 0
328: 		for cnt < 3 && sqlite.IsBusyOrLocked(err) {
329: 			cnt++
330: 			logger.Debug("Database locked, sleeping then retrying", "error", err, "sql", sql)
331: 			span.AddEvent("Database locked, sleeping then retrying",
332: 				trace.WithAttributes(attribute.String("error", err.Error())),
333: 				trace.WithAttributes(attribute.String("sql", sql)),
334: 			)
335: 			time.Sleep(100 * time.Millisecond)
336: 			err = mg.exec(ctx, m, sess)
337: 		}
338: 
339: 		if err != nil {
340: 			logger.Error("Exec failed", "error", err, "sql", sql)
341: 			record.Error = err.Error()
342: 			if !m.SkipMigrationLog() {
343: 				if _, err := sess.Table(mg.tableName).Insert(&record); err != nil {
344: 					return err
345: 				}
346: 			}
347: 			return err
348: 		}
349: 		record.Success = true
350: 		if !m.SkipMigrationLog() {
351: 			_, err = sess.Table(mg.tableName).Insert(&record)
352: 		}
353: 		return err
354: 	})
355: 	if err != nil {
356: 		return tracing.Errorf(span, "migration failed (id = %s): %w", m.Id(), err)
357: 	}
358: 
359: 	span.SetStatus(codes.Ok, "")
360: 
361: 	return nil
362: }
363: 
364: func (mg *Migrator) exec(ctx context.Context, m Migration, sess *xorm.Session) error {
365: 	logger := mg.Logger.FromContext(ctx)
366: 
367: 	start := time.Now()
368: 	logger.Info("Executing migration", "id", m.Id())
369: 
370: 	condition := m.GetCondition()
371: 	if condition != nil {
372: 		sql, args := condition.SQL(mg.Dialect)
373: 
374: 		if sql != "" {
375: 			logger.Debug("Executing migration condition SQL", "id", m.Id(), "sql", sql, "args", args)
376: 			results, err := sess.SQL(sql, args...).Query()
377: 			if err != nil {
378: 				logger.Error("Executing migration condition failed", "id", m.Id(), "error", err)
379: 				return err
380: 			}
381: 
382: 			if !condition.IsFulfilled(results) {
383: 				logger.Warn("Skipping migration: Already executed, but not recorded in migration log", "id", m.Id())
384: 				return nil
385: 			}
386: 		}
387: 	}
388: 
389: 	var err error
390: 	if codeMigration, ok := m.(CodeMigration); ok {
391: 		logger.Debug("Executing code migration", "id", m.Id())
392: 		err = codeMigration.Exec(sess, mg)
393: 	} else {
394: 		sql := m.SQL(mg.Dialect)
395: 		if strings.TrimSpace(sql) == "" {
396: 			logger.Debug("Skipping empty sql migration", "id", m.Id())
397: 		} else {
398: 			logger.Debug("Executing sql migration", "id", m.Id(), "sql", sql)
399: 			_, err = sess.Exec(sql)
400: 		}
401: 	}
402: 
403: 	if err != nil {
404: 		logger.Error("Executing migration failed", "id", m.Id(), "error", err, "duration", time.Since(start))
405: 		return err
406: 	}
407: 
408: 	logger.Info("Migration successfully executed", "id", m.Id(), "duration", time.Since(start))
409: 
410: 	return nil
411: }
