413: type dbTransactionFunc func(sess *xorm.Session) error
414: 
415: func (mg *Migrator) InTransaction(callback dbTransactionFunc) error {
416: 	sess := mg.DBEngine.NewSession()
417: 	defer sess.Close()
418: 
419: 	if err := sess.Begin(); err != nil {
420: 		return err
421: 	}
422: 
423: 	if err := callback(sess); err != nil {
424: 		if rollErr := sess.Rollback(); rollErr != nil {
425: 			return fmt.Errorf("failed to roll back transaction due to error: %s: %w", rollErr, err)
426: 		}
427: 
428: 		return err
429: 	}
430: 
431: 	if err := sess.Commit(); err != nil {
432: 		return err
433: 	}
434: 
435: 	return nil
436: }
437: 
438: func casRestoreOnErr(lock *atomic.Bool, o, n bool, casErr error, f func(LockCfg) error, lockCfg LockCfg) error {
439: 	if !lock.CompareAndSwap(o, n) {
440: 		return casErr
441: 	}
442: 	if err := f(lockCfg); err != nil {
443: 		// Automatically unlock/lock on error
444: 		lock.Store(o)
445: 		return err
446: 	}
447: 	return nil
448: }
