231: 
232: 	idxName := index.XName(tableName)
233: 
234: 	quotedCols := []string{}
235: 	for _, col := range index.Cols {
236: 		quotedCols = append(quotedCols, b.dialect.Quote(col))
237: 	}
238: 
239: 	return fmt.Sprintf("CREATE%s INDEX %v ON %v (%v);", unique, quote(idxName), quote(tableName), strings.Join(quotedCols, ","))
240: }
