317: // OrderBy normalizes ordering so that nulls end up last in sorting, which they do by default in both sqlite and mysql but not postgres
318: // order should be a string like `dashboard.id ASC`
319: func (db *PostgresDialect) OrderBy(order string) string {
320: 	nullSort := "FIRST"
321: 	normalizedOrder := strings.ToUpper(strings.TrimSpace(order))
322: 
323: 	if strings.HasSuffix(normalizedOrder, " DESC") {
324: 		nullSort = "LAST"
325: 	}
326: 
327: 	return fmt.Sprintf("%s NULLS %s", order, nullSort)
328: }
329: 
330: func (db *PostgresDialect) Unlock(cfg LockCfg) error {
331: 	// trying to release a previously-acquired exclusive session level advisory lock.
332: 	// it will either return true if the lock is successfully released or
333: 	// false if the lock was not held (in addition an SQL warning will be reported by the server)
334: 	query := "SELECT pg_advisory_unlock(?)"
335: 	var success bool
336: 
337: 	_, err := cfg.Session.SQL(query, cfg.Key).Get(&success)
338: 	if err != nil {
339: 		return err
340: 	}
341: 	if !success {
342: 		return ErrReleaseLockDB
343: 	}
344: 	return nil
345: }
346: 
347: func (db *PostgresDialect) GetDBName(dsn string) (string, error) {
348: 	if strings.HasPrefix(dsn, "postgres://") || strings.HasPrefix(dsn, "postgresql://") {
349: 		parsedDSN, err := pq.ParseURL(dsn)
350: 		if err != nil {
351: 			return "", err
352: 		}
353: 		dsn = parsedDSN
354: 	}
355: 	re := regexp.MustCompile(`dbname=(\w+)`)
356: 	submatch := re.FindSubmatch([]byte(dsn))
357: 	if len(submatch) < 2 {
358: 		return "", fmt.Errorf("failed to get database name")
359: 	}
360: 	return string(submatch[1]), nil
361: }
