58: func (db *SQLite3) SQLType(c *Column) string {
59: 	switch c.Type {
60: 	case DB_Date, DB_DateTime, DB_TimeStamp, DB_Time:
61: 		return DB_DateTime
62: 	case DB_TimeStampz:
63: 		return DB_Text
64: 	case DB_Char, DB_Varchar, DB_NVarchar, DB_TinyText, DB_Text, DB_MediumText, DB_LongText:
65: 		return DB_Text
66: 	case DB_Bit, DB_TinyInt, DB_SmallInt, DB_MediumInt, DB_Int, DB_Integer, DB_BigInt, DB_Bool:
67: 		return DB_Integer
68: 	case DB_Float, DB_Double, DB_Real:
69: 		return DB_Real
70: 	case DB_Decimal, DB_Numeric:
71: 		return DB_Numeric
72: 	case DB_TinyBlob, DB_Blob, DB_MediumBlob, DB_LongBlob, DB_Bytea, DB_Binary, DB_VarBinary:
73: 		return DB_Blob
74: 	case DB_Serial, DB_BigSerial:
75: 		c.IsPrimaryKey = true
76: 		c.IsAutoIncrement = true
77: 		c.Nullable = false
78: 		return DB_Integer
79: 	default:
80: 		return c.Type
81: 	}
82: }
