84: func (db *SQLite3) IndexCheckSQL(tableName, indexName string) (string, []any) {
85: 	args := []any{tableName, indexName}
86: 	sql := "SELECT 1 FROM " + db.Quote("sqlite_master") + " WHERE " + db.Quote("type") + "='index' AND " + db.Quote("tbl_name") + "=? AND " + db.Quote("name") + "=?"
87: 	return sql, args
88: }
89: 
90: func (db *SQLite3) ColumnCheckSQL(tableName, columnName string) (string, []any) {
91: 	// Use PRAGMA table_info to check if a column exists on a table. In SQLite, quoting with backticks inside
92: 	// pragma_table_info(<expr>) can be interpreted as an identifier/column. Instead, pass the table name as a
93: 	// string literal to avoid ambiguity. We cannot parameterize identifiers, but pragma_table_info accepts string
94: 	// literals, so we embed a single-quoted literal safely by replacing single quotes if any.
95: 	// Note: tableName is expected to be a trusted identifier from migrations.
96: 	safeTable := strings.ReplaceAll(tableName, "'", "''")
97: 	sql := "SELECT 1 FROM pragma_table_info('" + safeTable + "') WHERE name = ?"
98: 	return sql, []any{columnName}
99: }
100: 
101: func (db *SQLite3) DropIndexSQL(tableName string, index *Index) string {
102: 	quote := db.Quote
103: 	// var unique string
104: 	idxName := index.XName(tableName)
105: 	return fmt.Sprintf("DROP INDEX %v", quote(idxName))
106: }
