163: // UpsertSQL returns the upsert sql statement for SQLite dialect
164: func (db *SQLite3) UpsertSQL(tableName string, keyCols, updateCols []string) string {
165: 	str, _ := db.UpsertMultipleSQL(tableName, keyCols, updateCols, 1)
166: 	return str
167: }
168: 
169: // UpsertMultipleSQL returns the upsert sql statement for PostgreSQL dialect
170: func (db *SQLite3) UpsertMultipleSQL(tableName string, keyCols, updateCols []string, count int) (string, error) {
171: 	if count < 1 {
172: 		return "", fmt.Errorf("upsert statement must have count >= 1. Got %v", count)
173: 	}
174: 	columnsStr := strings.Builder{}
175: 	onConflictStr := strings.Builder{}
176: 	colPlaceHoldersStr := strings.Builder{}
177: 	setStr := strings.Builder{}
178: 
179: 	const separator = ", "
180: 	separatorVar := separator
181: 	for i, c := range updateCols {
182: 		if i == len(updateCols)-1 {
183: 			separatorVar = ""
184: 		}
185: 
186: 		columnsStr.WriteString(fmt.Sprintf("%s%s", db.Quote(c), separatorVar))
187: 		colPlaceHoldersStr.WriteString(fmt.Sprintf("?%s", separatorVar))
188: 		setStr.WriteString(fmt.Sprintf("%s=excluded.%s%s", db.Quote(c), db.Quote(c), separatorVar))
189: 	}
190: 
191: 	separatorVar = separator
192: 	for i, c := range keyCols {
193: 		if i == len(keyCols)-1 {
194: 			separatorVar = ""
195: 		}
196: 		onConflictStr.WriteString(fmt.Sprintf("%s%s", db.Quote(c), separatorVar))
197: 	}
198: 
199: 	valuesStr := strings.Builder{}
200: 	separatorVar = separator
201: 	colPlaceHolders := colPlaceHoldersStr.String()
202: 	for i := 0; i < count; i++ {
203: 		if i == count-1 {
204: 			separatorVar = ""
205: 		}
206: 		valuesStr.WriteString(fmt.Sprintf("(%s)%s", colPlaceHolders, separatorVar))
207: 	}
208: 
209: 	s := fmt.Sprintf(`INSERT INTO %s (%s) VALUES %s ON CONFLICT(%s) DO UPDATE SET %s`,
210: 		tableName,
211: 		columnsStr.String(),
212: 		valuesStr.String(),
213: 		onConflictStr.String(),
214: 		setStr.String(),
215: 	)
216: 	return s, nil
217: }
218: 
219: func (db *SQLite3) Concat(strs ...string) string {
220: 	return strings.Join(strs, " || ")
221: }
